module mux32to1 (
    input [31:0] input_data,   // 32 input lines
    input [4:0] select,     // 5-bit select line
    output reg out          // output line
);
    always @(*) begin
        case (select)
            5'b00000: out = input_data[0];
            5'b00001: out = input_data[1];
            5'b00010: out = input_data[2];
            5'b00011: out = input_data[3];
            5'b00100: out = input_data[4];
            5'b00101: out = input_data[5];
            5'b00110: out = input_data[6];
            5'b00111: out = input_data[7];
            5'b01000: out = input_data[8];
            5'b01001: out = input_data[9];
            5'b01010: out = input_data[10];
            5'b01011: out = input_data[11];
            5'b01100: out = input_data[12];
            5'b01101: out = input_data[13];
            5'b01110: out = input_data[14];
            5'b01111: out = input_data[15];
            5'b10000: out = input_data[16];
            5'b10001: out = input_data[17];
            5'b10010: out = input_data[18];
            5'b10011: out = input_data[19];
            5'b10100: out = input_data[20];
            5'b10101: out = input_data[21];
            5'b10110: out = input_data[22];
            5'b10111: out = input_data[23];
            5'b11000: out = input_data[24];
            5'b11001: out = input_data[25];
            5'b11010: out = input_data[26];
            5'b11011: out = input_data[27];
            5'b11100: out = input_data[28];
            5'b11101: out = input_data[29];
            5'b11110: out = input_data[30];
            5'b11111: out = input_data[31];
            default: out = 1'b0; // Default case
        endcase
    end
endmodule
